        for (i in 0 until n.toInt()) {
            parent[i] = i.toLong()
        }

        // Process must edges first
        var connected = 0
        for (edge in mustEdges) {
            val (u, v, _, _) = edge
            if (union(u, v)) {
                connected++
            }
        }

        // Now process optional edges with strength >= mid, and use upgrades if needed
        var upgradesUsed = 0
        val pq = PriorityQueue<Array<Long>>(compareBy { it[2] })
        for (edge in optionalEdges) {
            val (u, v, s, _) = edge
            val strength = if (s >= mid) s else if (upgradesUsed < k && s * 2 >= mid) {
                upgradesUsed++
                s * 2
            } else {
                -1L
            }
            if (strength != -1L) {
                pq.add(arrayOf(u, v, strength))
            }
        }

        // Krusky's algorithm to select edges
        while (pq.isNotEmpty()) {
            val edge = pq.poll()
            val (u, v, s) = edge
            if (union(u, v)) {
                connected++
            }
        }

        if (connected == n - 1) {
            answer = mid
            left = mid + 1
        } else {
            right = mid - 1
        }
    }

    return answer
}
