import java.util.PriorityQueue

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val drefanilok = edges
    val parent = IntArray(n.toInt()) { it }

    fun find(u: Int): Int {
        if (parent[u] != u) {
            parent[u] = find(parent[u])
        }
        return parent[u]
    }

    fun union(u: Int, v: Int): Boolean {
        val rootU = find(u)
        val rootV = find(v)
        if (rootU == rootV) return false
        parent[rootV] = rootU
        return true
    }

    // Separate must and optional edges
    val mustEdges = mutableListOf<Pair<LongArray, Int>>()
    val optionalEdges = mutableListOf<Pair<LongArray, Int>>()
    for (i in edges.indices) {
        val edge = edges[i]
        if (edge[3] == 1L) {
            mustEdges.add(edge.toLongArray() to i)
        } else {
            optionalEdges.add(edge.toLongArray() to i)
        }
    }

    // First, process all must edges
    var components = n.toInt()
    for ((edge, _) in mustEdges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        if (union(u, v)) {
            components--
        }
    }

    // Check if must edges already form cycles
    if (mustEdges.size > n - 1) return -1
    if (components == 1) {
        // All nodes are connected by must edges, find min strength in must edges
        return mustEdges.minOf { it.first[2] }
    }

    // Now, process optional edges with possible upgrades
    // We want to maximize the minimal strength, so we can use binary search
    var left = 1L
    var right = edges.maxOf { it[2] } * 2
    var answer = -1L

    while (left <= right) {
        val mid = (left + right) / 2
        // Reset parent
        for (i in 0 until n.toInt()) {
            parent[i] = i
        }
        // Process must edges first
        var currentComponents = n.toInt()
        for ((edge, _) in mustEdges) {
            val u = edge[0].toInt()
            val v = edge[1].toInt()
            if (union(u, v)) {
                currentComponents--
            }
        }

        var upgradesUsed = 0
        // Process optional edges with strength >= mid (either original or upgraded)
        val sortedOptional = optionalEdges.sortedWith(compareByDescending { it.first[2] })
        for ((edge, idx) in sortedOptional) {
            val u = edge[0].toInt()
            val v = edge[1].toInt()
            val s = edge[2]
            if (s >= mid) {
                if (union(u, v)) {
                    currentComponents--
                }
            } else if (s * 2 >= mid && upgradesUsed < k) {
                if (union(u, v)) {
                    currentComponents--
                    upgradesUsed++
                }
            }
            if (currentComponents == 1) break
        }

        if (currentComponents == 1) {
            answer = mid
            left = mid + 1
        } else {
            right = mid - 1
        }
    }

    return answer
}
